class Solution:
    def minSteps(self, n: int) -> int:
        if n == 1:
            return 0
        steps = 0
        clipboard = 1
        while n > 1:
            if n % clipboard == 0:
                steps += 1
                n -= clipboard
                clipboard *= 2
            else:
                clipboard -= n % clipboard
                steps += n % clipboard
        return steps

